import React, { Component } from "react";

class Tools extends Component {
  toolsList = [
    {
      id: 1,
      tools: [
        "JavaScript",
        "Angular",
        "ReactJS",
        "SASS",
        "HTML5",
        "PHP",
        "MySQL",
        "ExpressJS",
        "npm",
        "Git",
        "Bitbucket",
        "Jira",
        "Confluence",
        "NodeJS",
        "APIs",
        "Docker",
        "MongoDB",
        "Adobe CC",
        "FIgma",
      ],
    },
  ];
  render() {
    return (
      <div className="row">
        {this.toolsList.map((x) => (
          <span key={x.id}>{x}</span>
        ))}
      </div>
    );
  }
}

export default Tools;
